import 'package:flutter/material.dart';\nimport 'package:flutter_blue_plus/flutter_blue_plus.dart';\nimport 'package:nfc_manager/nfc_manager.dart';\nimport 'package:flutter_secure_storage/flutter_secure_storage.dart';\nimport 'package:provider/provider.dart';\nimport 'dart:async';\nimport 'dart:convert';\nimport 'dart:typed_data';\nimport 'package:crypto/crypto.dart';\n\n// ==================== MODELS ====================\n\nclass DigitalKey {\n  final String keyId;\n  final String vehicleId;\n  final String userId;\n  final Uint8List privateKey;\n  final Uint8List publicKey;\n  final DateTime issuedAt;\n  final DateTime expiresAt;\n  final List<String> permissions; // 'unlock', 'lock', 'start_engine'\n  final bool isActive;\n\n  DigitalKey({\n    required this.keyId,\n    required this.vehicleId,\n    required this.userId,\n    required this.privateKey,\n    required this.publicKey,\n    required this.issuedAt,\n    required this.expiresAt,\n    this.permissions = const ['unlock', 'lock'],\n    this.isActive = true,\n  });\n\n  bool get isExpired => DateTime.now().isAfter(expiresAt);\n\n  Map<String, dynamic> toJson() => {\n    'keyId': keyId,\n    'vehicleId': vehicleId,\n    'userId': userId,\n    'publicKey': base64Encode(publicKey),\n    'issuedAt': issuedAt.toIso8601String(),\n    'expiresAt': expiresAt.toIso8601String(),\n    'permissions': permissions,\n    'isActive': isActive,\n  };\n}\n\nclass VehicleDevice {\n  final String macAddress;\n  final String name;\n  final int rssi;\n  final DateTime lastSeen;\n  final bool isEncrypted;\n\n  VehicleDevice({\n    required this.macAddress,\n    required this.name,\n    required this.rssi,\n    required this.lastSeen,\n    this.isEncrypted = true,\n  });\n\n  double get signalStrength {\n    // Convert RSSI to 0-100% signal strength\n    if (rssi >= -50) return 100;\n    if (rssi <= -100) return 0;\n    return ((rssi + 100) * 2).toDouble();\n  }\n}\n\nclass AccessLog {\n  final String id;\n  final DateTime timestamp;\n  final String action; // 'unlock', 'lock', 'start_engine', 'emergency_unlock'\n  final String status; // 'success', 'failed', 'timeout'\n  final double? distance;\n  final String? errorMessage;\n\n  AccessLog({\n    required this.id,\n    required this.timestamp,\n    required this.action,\n    required this.status,\n    this.distance,\n    this.errorMessage,\n  });\n}\n\n// ==================== BLE SERVICE ====================\n\nclass BLEService with ChangeNotifier {\n  late FlutterBluePlus _flutterBluePlus;\n  StreamSubscription? _scanSubscription;\n  StreamSubscription? _connectionSubscription;\n\n  List<VehicleDevice> discoveredVehicles = [];\n  BluetoothDevice? connectedDevice;\n  BluetoothCharacteristic? authChallengeChar;\n  BluetoothCharacteristic? authResponseChar;\n  BluetoothCharacteristic? statusChar;\n\n  bool _isScanning = false;\n  bool get isScanning => _isScanning;\n\n  BLEService() {\n    _flutterBluePlus = FlutterBluePlus.instance;\n    _setupBLEListeners();\n  }\n\n  void _setupBLEListeners() {\n    _flutterBluePlus.onScanResults.listen((results) {\n      for (ScanResult r in results) {\n        if (r.device.name.contains('SmartCarAccess')) {\n          final vehicle = VehicleDevice(\n            macAddress: r.device.remoteId.str,\n            name: r.device.name,\n            rssi: r.rssi,\n            lastSeen: DateTime.now(),\n          );\n\n          // Add or update vehicle in list\n          final index = discoveredVehicles\n              .indexWhere((v) => v.macAddress == vehicle.macAddress);\n          if (index >= 0) {\n            discoveredVehicles[index] = vehicle;\n          } else {\n            discoveredVehicles.add(vehicle);\n          }\n          notifyListeners();\n        }\n      }\n    });\n  }\n\n  Future<void> startScan() async {\n    try {\n      _isScanning = true;\n      notifyListeners();\n\n      await _flutterBluePlus.startScan(\n        timeout: const Duration(seconds: 10),\n      );\n\n      _isScanning = false;\n      notifyListeners();\n    } catch (e) {\n      print('[BLE] Scan error: $e');\n      _isScanning = false;\n      notifyListeners();\n    }\n  }\n\n  Future<bool> connectToDevice(VehicleDevice vehicle) async {\n    try {\n      final device = BluetoothDevice(\n        remoteId: DeviceIdentifier(vehicle.macAddress),\n      );\n\n      await device.connect(timeout: const Duration(seconds: 10));\n      connectedDevice = device;\n\n      // Discover services\n      List<BluetoothService> services = await device.discoverServices();\n      for (var service in services) {\n        for (var char in service.characteristics) {\n          if (char.uuid.str == '0000-2A19-0000-1000-8000-00805F9B34FB') {\n            authChallengeChar = char;\n          } else if (char.uuid.str == '0000-2A1A-0000-1000-8000-00805F9B34FB') {\n            authResponseChar = char;\n          } else if (char.uuid.str == '0000-2A1B-0000-1000-8000-00805F9B34FB') {\n            statusChar = char;\n          }\n        }\n      }\n\n      notifyListeners();\n      return true;\n    } catch (e) {\n      print('[BLE] Connection error: $e');\n      return false;\n    }\n  }\n\n  Future<void> disconnect() async {\n    if (connectedDevice != null) {\n      await connectedDevice!.disconnect();\n      connectedDevice = null;\n      notifyListeners();\n    }\n  }\n\n  Stream<List<int>> listenToAuthChallenge() {\n    if (authChallengeChar == null) {\n      throw Exception('Auth challenge characteristic not found');\n    }\n    return authChallengeChar!.onValueReceived;\n  }\n\n  Future<void> sendAuthResponse(Uint8List response) async {\n    if (authResponseChar == null) {\n      throw Exception('Auth response characteristic not found');\n    }\n    await authResponseChar!.write(response);\n  }\n}\n\n// ==================== SECURITY SERVICE ====================\n\nclass SecurityService {\n  static const _secureStorage = FlutterSecureStorage();\n\n  // HMAC-SHA256 verification\n  static Uint8List calculateHMAC(\n    Uint8List key,\n    Uint8List data,\n  ) {\n    return Uint8List.fromList(\n      Hmac(sha256, key).convert(data).bytes,\n    );\n  }\n\n  // Generate authentication response\n  static Uint8List generateAuthResponse(\n    Uint8List sessionKey,\n    Uint8List challenge,\n    Uint8List nonce,\n  ) {\n    // Response = HMAC-SHA256(sessionKey, challenge || nonce || timestamp)\n    final timestamp = DateTime.now().millisecondsSinceEpoch;\n    final timestampBytes = Uint8List(8);\n    for (int i = 0; i < 8; i++) {\n      timestampBytes[i] = (timestamp >> (i * 8)) & 0xFF;\n    }\n\n    final data = Uint8List(\n      challenge.length + nonce.length + timestampBytes.length,\n    );\n    data.setRange(0, challenge.length, challenge);\n    data.setRange(challenge.length, challenge.length + nonce.length, nonce);\n    data.setRange(\n      challenge.length + nonce.length,\n      data.length,\n      timestampBytes,\n    );\n\n    return calculateHMAC(sessionKey, data);\n  }\n\n  // Store digital key securely\n  static Future<void> storeDigitalKey(DigitalKey key) async {\n    await _secureStorage.write(\n      key: key.keyId,\n      value: jsonEncode(key.toJson()),\n    );\n  }\n\n  // Retrieve digital key\n  static Future<DigitalKey?> retrieveDigitalKey(String keyId) async {\n    final json = await _secureStorage.read(key: keyId);\n    if (json == null) return null;\n\n    // Reconstruct DigitalKey from JSON\n    // (Implementation omitted for brevity)\n    return null;\n  }\n\n  // Delete digital key\n  static Future<void> deleteDigitalKey(String keyId) async {\n    await _secureStorage.delete(key: keyId);\n  }\n}\n\n// ==================== NFC SERVICE ====================\n\nclass NFCService {\n  static Future<bool> isAvailable() async {\n    return await NfcManager.instance.isAvailable();\n  }\n\n  static Future<void> startNFCSession() async {\n    await NfcManager.instance.startSession(\n      onDiscovered: (NfcTag tag) async {\n        print('[NFC] Tag discovered: ${tag.data}');\n        // Parse NFC tag and verify emergency key\n        // Implementation for emergency access\n      },\n    );\n  }\n\n  static Future<void> stopNFCSession() async {\n    await NfcManager.instance.stopSession();\n  }\n}\n\n// ==================== AUTHENTICATION ENGINE ====================\n\nclass AuthenticationEngine with ChangeNotifier {\n  final BLEService _bleService;\n  final SecurityService _securityService = SecurityService();\n\n  String? _authStatus;\n  String? get authStatus => _authStatus;\n\n  bool _isAuthenticating = false;\n  bool get isAuthenticating => _isAuthenticating;\n\n  AuthenticationEngine(this._bleService);\n\n  Future<bool> authenticate(DigitalKey key) async {\n    try {\n      _isAuthenticating = true;\n      _authStatus = 'Authenticating...';\n      notifyListeners();\n\n      // Listen for challenge\n      final challengeStream = _bleService.listenToAuthChallenge();\n\n      // Get first challenge\n      final challengeData =\n          await challengeStream.first.timeout(Duration(seconds: 10));\n\n      // Extract challenge and nonce from data\n      final challenge = Uint8List.fromList(challengeData.sublist(0, 16));\n      final nonce = Uint8List.fromList(challengeData.sublist(16, 32));\n\n      // Generate response using session key (derived from private key)\n      final sessionKey = key.privateKey.sublist(0, 32);\n      final response = SecurityService.generateAuthResponse(\n        sessionKey,\n        challenge,\n        nonce,\n      );\n\n      // Send response\n      await _bleService.sendAuthResponse(response);\n\n      _authStatus = 'Authentication successful';\n      notifyListeners();\n      return true;\n    } catch (e) {\n      _authStatus = 'Authentication failed: $e';\n      notifyListeners();\n      return false;\n    } finally {\n      _isAuthenticating = false;\n      notifyListeners();\n    }\n  }\n}\n\n// ==================== MAIN APP ====================\n\nvoid main() async {\n  WidgetsFlutterBinding.ensureInitialized();\n  runApp(const SmartCarAccessApp());\n}\n\nclass SmartCarAccessApp extends StatelessWidget {\n  const SmartCarAccessApp({Key? key}) : super(key: key);\n\n  @override\n  Widget build(BuildContext context) {\n    return MultiProvider(\n      providers: [\n        ChangeNotifierProvider(create: (_) => BLEService()),\n        ChangeNotifierProxyProvider<BLEService, AuthenticationEngine>(\n          create: (_) => AuthenticationEngine(BLEService()),\n          update: (_, bleService, __) =>\n              AuthenticationEngine(bleService),\n        ),\n      ],\n      child: MaterialApp(\n        title: 'Smart Car Access',\n        theme: ThemeData(\n          primarySwatch: Colors.blue,\n          useMaterial3: true,\n        ),\n        home: const HomeScreen(),\n      ),\n    );\n  }\n}\n\nclass HomeScreen extends StatefulWidget {\n  const HomeScreen({Key? key}) : super(key: key);\n\n  @override\n  State<HomeScreen> createState() => _HomeScreenState();\n}\n\nclass _HomeScreenState extends State<HomeScreen> {\n  late BLEService _bleService;\n  late AuthenticationEngine _authEngine;\n  DigitalKey? _selectedKey;\n\n  @override\n  void initState() {\n    super.initState();\n    _bleService = context.read<BLEService>();\n    _authEngine = context.read<AuthenticationEngine>();\n  }\n\n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      appBar: AppBar(\n        title: const Text('Smart Car Access'),\n        centerTitle: true,\n      ),\n      body: Column(\n        children: [\n          // Status section\n          Padding(\n            padding: const EdgeInsets.all(16.0),\n            child: Consumer<BLEService>(\n              builder: (context, bleService, _) {\n                return Card(\n                  child: Padding(\n                    padding: const EdgeInsets.all(16.0),\n                    child: Column(\n                      children: [\n                        Text(\n                          bleService.connectedDevice?.remoteId.str ??\n                              'Not Connected',\n                          style: const TextStyle(\n                            fontSize: 18,\n                            fontWeight: FontWeight.bold,\n                          ),\n                        ),\n                        const SizedBox(height: 8),\n                        if (bleService.connectedDevice != null)\n                          const Text(\n                            'Connected to Vehicle',\n                            style: TextStyle(color: Colors.green),\n                          )\n                        else\n                          const Text(\n                            'Tap \"Connect\" to find vehicles',\n                            style: TextStyle(color: Colors.orange),\n                          ),\n                      ],\n                    ),\n                  ),\n                );\n              },\n            ),\n          ),\n\n          // Vehicle list\n          Expanded(\n            child: Consumer<BLEService>(\n              builder: (context, bleService, _) {\n                if (bleService.discoveredVehicles.isEmpty &&\n                    !bleService.isScanning) {\n                  return const Center(\n                    child: Text('No vehicles found. Tap \"Connect\" to scan.'),\n                  );\n                }\n\n                return ListView.builder(\n                  itemCount: bleService.discoveredVehicles.length,\n                  itemBuilder: (context, index) {\n                    final vehicle = bleService.discoveredVehicles[index];\n                    return ListTile(\n                      title: Text(vehicle.name),\n                      subtitle: Text(\n                        'Signal: ${vehicle.signalStrength.toInt()}%',\n                      ),\n                      onTap: () => _showConnectDialog(vehicle),\n                    );\n                  },\n                );\n              },\n            ),\n          ),\n\n          // Control buttons\n          Padding(\n            padding: const EdgeInsets.all(16.0),\n            child: Column(\n              children: [\n                ElevatedButton.icon(\n                  onPressed: () => _bleService.startScan(),\n                  icon: const Icon(Icons.search),\n                  label: const Text('Scan for Vehicles'),\n                ),\n                const SizedBox(height: 8),\n                ElevatedButton.icon(\n                  onPressed: _selectedKey != null\n                      ? () => _performUnlock()\n                      : null,\n                  icon: const Icon(Icons.lock_open),\n                  label: const Text('Unlock'),\n                ),\n                const SizedBox(height: 8),\n                ElevatedButton.icon(\n                  onPressed: _selectedKey != null\n                      ? () => _performLock()\n                      : null,\n                  icon: const Icon(Icons.lock),\n                  label: const Text('Lock'),\n                ),\n              ],\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n\n  void _showConnectDialog(VehicleDevice vehicle) {\n    showDialog(\n      context: context,\n      builder: (context) => AlertDialog(\n        title: Text(vehicle.name),\n        content: Text('Connect to ${vehicle.name}?'),\n        actions: [\n          TextButton(\n            onPressed: () => Navigator.pop(context),\n            child: const Text('Cancel'),\n          ),\n          ElevatedButton(\n            onPressed: () async {\n              final success = await _bleService.connectToDevice(vehicle);\n              if (success && mounted) {\n                Navigator.pop(context);\n                ScaffoldMessenger.of(context).showSnackBar(\n                  const SnackBar(content: Text('Connected to vehicle')),\n                );\n              }\n            },\n            child: const Text('Connect'),\n          ),\n        ],\n      ),\n    );\n  }\n\n  Future<void> _performUnlock() async {\n    if (_selectedKey == null) return;\n\n    final success = await _authEngine.authenticate(_selectedKey!);\n    if (mounted) {\n      ScaffoldMessenger.of(context).showSnackBar(\n        SnackBar(\n          content: Text(success ? 'Vehicle unlocked!' : 'Unlock failed'),\n          backgroundColor: success ? Colors.green : Colors.red,\n        ),\n      );\n    }\n  }\n\n  Future<void> _performLock() async {\n    ScaffoldMessenger.of(context).showSnackBar(\n      const SnackBar(content: Text('Vehicle locked')),\n    );\n  }\n}\n"